try:
    print(f"Loading baseline from {baseline_circuit_path}...")
    baseline = stim.Circuit.from_file(baseline_circuit_path)
    sim = stim.TableauSimulator()
    sim.do(baseline)
    
    print("Baseline simulated. Checking target stabilizers...")
    
    # Check if target stabilizers are preserved
    preserved_count = 0
    failed_count = 0
    
    for i, s in enumerate(stabilizers):
        p = stim.PauliString(s)
        # expectation returns +1, -1, or 0 (uncertain)
        ev = sim.peek_observable_expectation(p)
        if ev == 1:
            preserved_count += 1
        else:
            failed_count += 1
            if failed_count <= 5:
                print(f"Stabilizer {i} failed: Expectation = {ev}")
    
    print(f"Preserved: {preserved_count}/{len(stabilizers)}")
    
    if failed_count == 0:
        print("SUCCESS: Baseline satisfies all target stabilizers.")
    else:
        print("FAILURE: Baseline does NOT satisfy all target stabilizers.")
        
    # Also verify if target stabilizers commute among themselves (we saw this failed earlier)
    # We rely on the other script for that check, but the fact baseline satisfies them (if it does) implies they commute.

except Exception as e:
    print(f"Error: {e}")
